solution_code:
#include <iostream>
#include <string>

class Bird
{
protected:
    int m_wingSpan{};

public:
    Bird(int wingSpan)
        : m_wingSpan{ wingSpan }
    {
    }

    void showWings() const { std::cout << "wings: " << m_wingSpan << '\n'; }

    std::string name() const { return "Bird"; }
};

class Fish
{
protected:
    int m_depth{};

public:
    Fish(int depth)
        : m_depth{ depth }
    {
    }

    void showDepth() const { std::cout << "depth: " << m_depth << '\n'; }

    std::string name() const { return "Fish"; }
};

class FlyingFish : public Bird, public Fish
{
public:
    FlyingFish(int wingSpan, int depth)
        : Bird{ wingSpan }
        , Fish{ depth }
    {
    }

    std::string name() const { return "FlyingFish"; }
};

int main()
{
    int wingSpan{};
    int depth{};
    std::cin >> wingSpan >> depth;

    FlyingFish ff{ wingSpan, depth };
    ff.showWings();
    ff.showDepth();
    std::cout << "name: " << ff.name() << '\n';

    return 0;
}

